'use client';
import { useEffect, useRef, useState } from 'react';
import { PIXEL_CANDLESTICK_CHART_HTML } from './PixelCandlestickChart-dom';

// AUTO-GENERATED by cloner/src/lib/pixel_render_clone.mjs.
// Captured HTML lives in ./PixelCandlestickChart-dom.ts.
// Source URI: requested-0f055.html @ WIDGET_TYPE_CHART
// Render-to-match pattern: production CSS styles production DOM, so we
